    def make_args(self, switch, mismatch_seed, gumbel_temp, hard_gumbel):
        """Sample multiplicative mismatch delta ~ N(1, sigma^2) per weight."""
        key = jrandom.PRNGKey(mismatch_seed)
        k1, k2, k3 = jrandom.split(key, 3)
        sigma = 0.05
        _Wz = (self.a_trainable[0:4096] * (1.0 + sigma * jrandom.normal(k1, (4096,)))).reshape((64, 64))
        _Wx = (self.a_trainable[4096:8192] * (1.0 + sigma * jrandom.normal(k2, (4096,)))).reshape((64, 64))
        _bx = (self.a_trainable[8192:8256] * (1.0 + sigma * jrandom.normal(k3, (64,))))
        return (_Wz, _Wx, _bx)

    def ode_fn(self, t, y, args):
        """dy/dt = [dz/dt, 0]  where dz/dt = tanh(W_z@z + W_x@x + b_x) - z."""
        Wz, Wx, bx = args
        z = y[:64]
        x = y[64:]
        dz = jnp.tanh(Wz @ z + Wx @ x + bx) - z
        dx = jnp.zeros(64)
        return jnp.concatenate([dz, dx])

    def noise_fn(self, t, y, args):
        return jnp.zeros(128)

    def readout(self, y):
        """Return z* from the final saved time point."""
        return y[-1, :64]


